package util

import "fmt"

type EnumItem struct {
	Key   string `json:"key"`   // 枚举key（如 "pending"）
	Value string `json:"value"` // 枚举值（如 "排队中"）
}

// EnumProvider is an interface for enum providers
type EnumProvider interface {
	GetEnum() []EnumItem
}

// EnumRegistry 枚举注册表
type EnumRegistry struct {
	providers map[string]EnumProvider
}

// NewEnumRegistry 创建新的枚举注册表
func NewEnumRegistry() *EnumRegistry {
	return &EnumRegistry{
		providers: make(map[string]EnumProvider),
	}
}

// Register 注册枚举提供者
func (r *EnumRegistry) Register(enumType string, provider EnumProvider) {
	r.providers[enumType] = provider
}

// GetEnum 获取枚举值
func (r *EnumRegistry) GetEnum(enumType string) (interface{}, error) {
	if provider, exists := r.providers[enumType]; exists {
		return provider.GetEnum(), nil
	}
	return nil, fmt.Errorf("enum type '%s' not found", enumType)
}

// GetAvailableTypes 获取可用的枚举类型
func (r *EnumRegistry) GetAvailableTypes() []string {
	types := make([]string, 0, len(r.providers))
	for t := range r.providers {
		types = append(types, t)
	}
	return types
}

