package common

import (
	"net/http"

	"github.com/gin-gonic/gin"
)

// 常用错误码定义
const (
	CodeSuccess      = "00000" // 成功
	CodeBadRequest   = "400"   // 请求参数错误
	CodeUnauthorized = "401"   // 未授权
	CodeForbidden    = "403"   // 禁止访问
	CodeNotFound     = "404"   // 资源不存在
	CodeConflict     = "409"   // 资源冲突
	CodeInternalErr  = "500"   // 内部服务器错误
)

// BaseResponse 统一 API 响应结构
type BaseResponse struct {
	Code     string `json:"code" example:"00000"` // 业务状态码
	Msg      string `json:"msg" example:"ok"`     // 响应消息
	RespBody any    `json:"respBody"`             // 响应数据
}

// Success 创建成功响应
func Success(data any) *BaseResponse {
	return &BaseResponse{
		Code:     CodeSuccess,
		Msg:      "ok",
		RespBody: data,
	}
}

// SuccessWithMessage 创建带自定义消息的成功响应
func SuccessWithMessage(message string, data any) *BaseResponse {
	return &BaseResponse{
		Code:     CodeSuccess,
		Msg:      message,
		RespBody: data,
	}
}

// Error 创建错误响应
func Error(code string, message string) *BaseResponse {
	return &BaseResponse{
		Code:     code,
		Msg:      message,
		RespBody: nil,
	}
}

// BadRequest 创建 400 错误响应
func BadRequest(message string) *BaseResponse {
	return Error(CodeBadRequest, message)
}

// Unauthorized 创建 401 错误响应
func Unauthorized(message string) *BaseResponse {
	return Error(CodeUnauthorized, message)
}

// Forbidden 创建 403 错误响应
func Forbidden(message string) *BaseResponse {
	return Error(CodeForbidden, message)
}

// NotFound 创建 404 错误响应
func NotFound(message string) *BaseResponse {
	return Error(CodeNotFound, message)
}

// InternalError 创建 500 错误响应
func InternalError(message string) *BaseResponse {
	return Error(CodeInternalErr, message)
}

// Respond 统一响应辅助函数
func Respond(c *gin.Context, resp *BaseResponse) {
	c.JSON(http.StatusOK, resp)
}

// RespondSuccess 成功响应
func RespondSuccess(c *gin.Context, data any) {
	Respond(c, Success(data))
}

// RespondSuccessWithMessage 带消息的成功响应
func RespondSuccessWithMessage(c *gin.Context, message string, data any) {
	Respond(c, SuccessWithMessage(message, data))
}

// RespondBadRequest 400 错误响应
func RespondBadRequest(c *gin.Context, message string) {
	Respond(c, BadRequest(message))
}

// RespondUnauthorized 401 错误响应
func RespondUnauthorized(c *gin.Context, message string) {
	Respond(c, Unauthorized(message))
}

// RespondForbidden 403 错误响应
func RespondForbidden(c *gin.Context, message string) {
	Respond(c, Forbidden(message))
}

// RespondNotFound 404 错误响应
func RespondNotFound(c *gin.Context, message string) {
	Respond(c, NotFound(message))
}

// RespondInternalError 500 错误响应
func RespondInternalError(c *gin.Context, message string) {
	Respond(c, InternalError(message))
}

